callout.example:
const { div, span } = tags;
import { icon } from 'decantr/components';

div({ class: css('_flex _gap3 _p4 _r2 _bgprimary/10 _bcprimary/30 _border') },
  icon('lightbulb', { size: '18px', class: css('_fgprimary') }),
  div({ class: css('_flex _col _gap1') },
    span({ class: css('_label _bold') }, 'Pro Tip'),
    span({ class: css('_textsm') }, 'Use semantic colors for consistent theming.')
  )
)

code-block.example:
const { div, pre, code, span } = tags;
import { icon } from 'decantr/components';

div({ class: css('_r2 _bgmuted/30 _border _bcborder/50 _overflow[hidden]') },
  div({ class: css('_flex _aic _jcsb _px4 _py2 _bgmuted/20 _borderB _bcborder/50') },
    span({ class: css('_caption _fgmutedfg _uppercase') }, 'js'),
    button({ class: css('_flex _aic _gap1 _px2 _py1 _r1 _textsm _fgmutedfg') }, icon('copy', { size: '14px' }), 'Copy')
  ),
  pre({ class: css('_p4 _overflow[auto]') },
    code({ class: css('_fgfg') }, 'const hello = "world";')
  )
)

prompt-box.example:
const { div, p, span } = tags;
import { icon } from 'decantr/components';

div({ class: css('_flex _col _gap2 _p4 _r2 _bg[linear-gradient(135deg,var(--c-primary)/10,var(--c-primary)/5)] _border _bcprimary/30') },
  div({ class: css('_flex _aic _gap2 _textsm _fgprimary _fw[500]') },
    icon('message-square', { size: '16px' }),
    span('Try this prompt:')
  ),
  p({ class: css('_textbase _lhrelaxed _fgfg _italic') }, '"Add a settings page with user profile form"')
)
